import { calculateWinRate } from './task03';

describe('calculateWinRate', () => {
  it('calculates win rate correctly', () => {
    expect(calculateWinRate(3, 4)).toBe(0.75);
  });

  it('returns 0 when no games', () => {
    expect(calculateWinRate(0, 0)).toBe(0);
  });

  it('returns 1 when wins exceed total', () => {
    expect(calculateWinRate(5, 3)).toBe(1);
  });
});
